class Solution {
public:
    int minimumLength(string s) {
        int length = s.length();
        int result = length;
        for (int i = 0; i < length; i++) {
            for (int j = i + 1; j < length; j++) {
                if (s[i] == s[j] && s.substr(i, 2) == s.substr(j, 2)) {
                    result = min(result, length - i - j);
                }
            }
        }
        return result;
    }
};
```

